#include <bits/stdc++.h>
using namespace std;
struct block{
	int tp,t;
	bool die;
}g[3003][3003];
int di[4][2]={{-1,0},{1,0},{0,-1},{0,1}};
int n,m,q,r,k,cf[3003][3003],sum[3003][3003],ans;
bool nl[3003][3003];
void bfs(int t,int sx,int sy){
	queue<int> x,y;
	x.push(sx),y.push(sy);
	while(x.size()){
		int fx=x.front(),fy=y.front();
		x.pop(),y.pop();
		for(int i=0;i<4;i++){
			int xx=fx+di[i][0],yy=fy+di[i][1];
			if(xx>0 && yy>0 && xx<=n && yy<=m && g[xx][yy].tp!=1){
				if(g[xx][yy].tp==2){
					if(g[xx][yy].t+k>=t){
						if(g[xx][yy].die==false)
							g[xx][yy].die=1,ans++,x.push(xx),y.push(yy);
						if(g[fx][fy].die==false)
							g[fx][fy].die=1,ans++;
					}
					if(g[xx][yy].die)
						if(g[fx][fy].die==false)
							g[fx][fy].die=1,ans++;
				}else if(nl[xx][yy]){
					g[xx][yy]={2,0,1};
					ans++;
					if(g[fx][fy].die==false)
						g[fx][fy].die=1,ans++;
					x.push(xx),y.push(yy);
				}
			}
		}
	}
}
int main(){
	//freopen("lake.in","r",stdin);
	scanf("%d%d%d%d%d",&n,&m,&q,&r,&k);
	for(int i=0;i<q;i++){
		int a,b,c,d;
		scanf("%d%d%d%d",&a,&b,&c,&d);
		cf[a][b]++,cf[a][d+1]--,cf[c+1][b]--,cf[c+1][d+1]++; 
	}
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++){
			sum[i][j]=cf[i][j]+sum[i-1][j]+sum[i][j-1]-sum[i-1][j-1];
			if(sum[i][j])
				nl[i-1][j]=nl[i+1][j]=nl[i][j-1]=nl[i][j+1]=1;
			g[i][j]={sum[i][j],0,false};
		}
	for(int i=0;i<r;i++){
		int t,x,y;
		scanf("%d%d%d",&t,&x,&y);
		g[x][y]={2,t,nl[x][y]};
		ans+=nl[x][y];
		bfs(t,x,y);
	}
	/*for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++)
			printf("%d ",g[i][j].die);
		printf("\n");
	}*/
	printf("%d",ans);
	return 0;
}
